import { RootLogger } from "@workleap/logging";

class DummyLogger implements RootLogger {
    getName() {
        return DummyLogger.name;
    }
    withText() {
        return this;
    }
    withError() {
        return this;
    }
    withObject() {
        return this;
    }
    debug() {}
    information() {}
    warning() {}
    error() {}
    critical() {}
    startScope() {
        return new DummyLoggerScope();
    }
}

import { LoggerScope } from "@workleap/logging";

class DummyLoggerScope implements LoggerScope {
    withText() {
        return this;
    }
    withError() {
        return this;
    }
    withObject() {
        return this;
    }
    debug() {}
    information() {}
    warning() {}
    error() {}
    critical() {}
    end() {}
}

